(function () {
  'use strict';
  const fotosHero = [
    'fotos/foto1.jpg',
    'fotos/foto2.jpg',
  ];
  const fotosGaleria = [
  'fotos/foto3.jpg',
  'fotos/foto4.jpg',
  'fotos/foto5.jpg',
  'fotos/foto6.jpg',
  'fotos/foto7.jpg',
  'fotos/foto8.jpg',
  'fotos/foto9.jpg',
  'fotos/foto10.jpg',
];
const overlayFotos = document.querySelector('.more-photos .overlay');
if (overlayFotos) {
  const fotosExibidas = 4; 
  const restantes = fotosGaleria.length - fotosExibidas;
  if (restantes > 0) {
    overlayFotos.textContent = `+${restantes + 1} fotos`;
  } else {
    overlayFotos.style.display = 'none';
  }
}
  const lightbox        = document.getElementById('lightbox');
  const lightboxContent = document.getElementById('lightbox-content');
  const lightboxClose   = document.getElementById('lightbox-close');
  const btnPrev         = lightbox.querySelector('.prev');
  const btnNext         = lightbox.querySelector('.next');
  let fotoAtual  = 0;
  let listaAtiva = fotosGaleria;
  function abrirLightbox(lista, index) {
    listaAtiva = lista;
    fotoAtual  = index;
    renderFoto();
    lightbox.classList.add('open');
    document.body.style.overflow = 'hidden';
  }
  function fecharLightbox() {
    lightbox.classList.remove('open');
    document.body.style.overflow = '';
  }
  function renderFoto() {
    lightboxContent.innerHTML =
      `<img src="${listaAtiva[fotoAtual]}" alt="Foto ${fotoAtual + 1}">`;
    btnPrev.style.display = fotoAtual === 0 ? 'none' : 'block';
    btnNext.style.display = fotoAtual === listaAtiva.length - 1 ? 'none' : 'block';
  }
  function navegar(direcao) {
    const novoIndice = fotoAtual + direcao;
    if (novoIndice < 0 || novoIndice >= listaAtiva.length) return;
    fotoAtual = novoIndice;
    renderFoto();
  }
  document.querySelectorAll('[data-hero]').forEach(slot => {
    slot.addEventListener('click', () =>
      abrirLightbox(fotosHero, Number(slot.dataset.hero))
    );
  });
  document.querySelectorAll('.galeria .foto-slot').forEach(slot => {
    slot.addEventListener('click', () =>
      abrirLightbox(fotosGaleria, Number(slot.dataset.index ?? 0))
    );
  });
  btnPrev.addEventListener('click', () => navegar(-1));
  btnNext.addEventListener('click', () => navegar(+1));
  lightboxClose.addEventListener('click', fecharLightbox);
  lightbox.addEventListener('click', e => { if (e.target === lightbox) fecharLightbox(); });
  document.addEventListener('keydown', e => {
    if (!lightbox.classList.contains('open')) return;
    if (e.key === 'Escape')     fecharLightbox();
    if (e.key === 'ArrowLeft')  navegar(-1);
    if (e.key === 'ArrowRight') navegar(+1);
  });
  const btnAbrirVideo  = document.getElementById('abrirVideo');
  const videoLightbox  = document.getElementById('videoLightbox');
  const btnFecharVideo = document.getElementById('fecharVideo');
  const videoCasa      = document.getElementById('videoCasa');
  function abrirVideo() {
    videoLightbox.classList.add('open');
    document.body.style.overflow = 'hidden';
    videoCasa.play();
  }
  function fecharVideo() {
    videoCasa.pause();
    videoCasa.currentTime = 0;
    videoLightbox.classList.remove('open');
    document.body.style.overflow = '';
  }
  btnAbrirVideo?.addEventListener('click', abrirVideo);
  btnAbrirVideo?.addEventListener('keydown', e => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); abrirVideo(); }
  });
  btnFecharVideo?.addEventListener('click', fecharVideo);
  videoLightbox?.addEventListener('click', e => { if (e.target === videoLightbox) fecharVideo(); });
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && videoLightbox?.classList.contains('open')) fecharVideo();
  });
})();